function sqlIdentifier(value) {
  if (!/^[a-zA-Z0-9_]+$/.test(String(value))) {
    throw new Error(`Nome de banco inválido: ${value}`);
  }

  return `\`${value}\``;
}

const tableName = `${sqlIdentifier(dbName)}.\`hotmart20\``;

function normalizeKey(key) {
  return String(key || '')
    .replace(/^\uFEFF/, '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/\s+/g, ' ')
    .trim()
    .toLowerCase();
}

function normalizeValue(value) {
  if (value === undefined || value === null) return null;

  if (typeof value === 'string') {
    const v = value.trim();

    if (
      v === '' ||
      v.toLowerCase() === '(none)' ||
      v.toLowerCase() === 'none' ||
      v.toLowerCase() === 'null' ||
      v.toLowerCase() === 'undefined'
    ) {
      return null;
    }

    return v;
  }

  return value;
}

function buildNormalizedRow(row) {
  const normalized = {};

  for (const [key, value] of Object.entries(row)) {
    normalized[normalizeKey(key)] = normalizeValue(value);
  }

  return normalized;
}

function get(row, aliases) {
  for (const alias of aliases) {
    const value = row[normalizeKey(alias)];

    if (value !== undefined && value !== null && value !== '') {
      return value;
    }
  }

  return null;
}

function sqlValue(value) {
  value = normalizeValue(value);

  if (value === null || value === undefined || value === '') {
    return 'NULL';
  }

  return `'${String(value).replace(/'/g, "''")}'`;
}

function cleanPhone(value, country) {
  value = normalizeValue(value);

  if (!value) return null;

  let phone = String(value)
    .replace(/undefined/gi, '')
    .replace(/\D+/g, '');

  if (!phone) return null;

  const isBrazil = String(country || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .includes('brasil');

  if (isBrazil && !phone.startsWith('55')) {
    phone = `55${phone}`;
  }

  return phone;
}

function parseDate(value) {
  value = normalizeValue(value);

  if (!value) return null;

  const s = String(value).trim();

  // Formato: 2026-07-08 13:45:22
  if (/^\d{4}-\d{2}-\d{2}/.test(s)) {
    return s.replace('T', ' ').slice(0, 19);
  }

  // Formato: 08/07/2026 13:45:22
  const br = s.match(/^(\d{2})\/(\d{2})\/(\d{4})(?:\s+(\d{2}:\d{2}(?::\d{2})?))?/);

  if (br) {
    const [, dd, mm, yyyy, timeRaw] = br;
    const time = timeRaw
      ? timeRaw.length === 5
        ? `${timeRaw}:00`
        : timeRaw
      : '00:00:00';

    return `${yyyy}-${mm}-${dd} ${time}`;
  }

  return null;
}

function minusDays(dateString, days) {
  if (!dateString) return null;

  const date = new Date(dateString.replace(' ', 'T'));

  if (Number.isNaN(date.getTime())) return dateString;

  date.setDate(date.getDate() - days);

  const yyyy = date.getFullYear();
  const mm = String(date.getMonth() + 1).padStart(2, '0');
  const dd = String(date.getDate()).padStart(2, '0');
  const hh = String(date.getHours()).padStart(2, '0');
  const mi = String(date.getMinutes()).padStart(2, '0');
  const ss = String(date.getSeconds()).padStart(2, '0');

  return `${yyyy}-${mm}-${dd} ${hh}:${mi}:${ss}`;
}

function normalizeStatus(value) {
  value = normalizeValue(value);

  if (!value) return 'Desconhecido';

  const s = String(value).trim();

  const map = {
    'Aprovado': 'PURCHASE_APPROVED',
