    'tipo_do_order_bump',
    'Tipo do Order Bump'
  ]);

  if (String(tipoOrderBump || '').trim() === '1') return '1';

  if (transacaoPrincipal) return '1';

  if (ferramenta && String(ferramenta).toLowerCase().includes('order bump')) {
