  data.codigo_da_transacao = get(row, [
    'codigo_da_transacao',
    'Código da transação',
    'Transação',
    'chave'
  ]);

  const missingRequiredFields = validateRequiredFields(data);

  if (missingRequiredFields.includes('codigo_da_transacao')) {
    output.push({
      json: {
        skipped: true,
        critical: true,
        reason: 'codigo_da_transacao ausente',
        missingRequiredFields,
        unknownColumns: columnValidation.unknownColumns,
        receivedColumns: columnValidation.receivedColumns,
        row: originalRow
      }
    });

    continue;
