  data.status_da_transacao = normalizeStatus(data.status_da_transacao);

  data.data_da_transacao = parseDate(data.data_da_transacao);

  data.confirmacao_do_pagamento = parseDate(data.confirmacao_do_pagamento);

  data.data_de_vencimento_vouchers = parseDate(data.data_de_vencimento_vouchers);

  // Regra antiga: PURCHASE_COMPLETE menos 7 dias
