  data.metodo_de_pagamento = normalizePayment(data.metodo_de_pagamento);

  data.venda_feita_como = normalizeRole(data.venda_feita_como);

  data.telefone = cleanPhone(data.telefone, data.pais);

  data.tipo_do_order_bump = isOrderBump(row, data.codigo_da_transacao);

  const columnNames = Object.keys(columns);

  const insertColumns = columnNames
    .map(column => `\`${column}\``)
    .join(',\n  ');

  const insertValues = columnNames
    .map(column => sqlValue(data[column]))
    .join(',\n  ');

  const updateClause = columnNames
    .filter(column => column !== 'codigo_da_transacao')
    .map(column => `\`${column}\` = VALUES(\`${column}\`)`)
    .join(',\n  ');

  const query = `
INSERT INTO ${tableName} (
  ${insertColumns}
) VALUES (
  ${insertValues}
)
ON DUPLICATE KEY UPDATE
  ${updateClause};
`.trim();

  output.push({
    json: {
      codigo_da_transacao: data.codigo_da_transacao,
      status_da_transacao: data.status_da_transacao,
      data_da_transacao: data.data_da_transacao,
      produto: data.produto,
      codigo_do_produto: data.codigo_do_produto,
      tipo_do_order_bump: data.tipo_do_order_bump,

      validation: {
        hasUnknownColumns: columnValidation.unknownColumns.length > 0,
        unknownColumns: columnValidation.unknownColumns,
        missingRequiredFields
      },

      query
    }
  });
}

return output;

