    'Produtor(a)': 'PRODUCER',
    'Afiliado': 'AFFILIATE',
    'Afiliado(a)': 'AFFILIATE',
    'Coprodutor': 'COPRODUCER',
    'Coprodutor(a)': 'COPRODUCER'
  };

  if (map[s]) return map[s];

  if (['PRODUCER', 'AFFILIATE', 'COPRODUCER'].includes(s)) return s;

  return s;
}

function isOrderBump(row, codigoTransacao) {
  const ferramenta = get(row, [
    'Ferramenta de Venda',
    'Meio de Pagamento',
    'Ferramenta de venda'
  ]);

  const transacaoPrincipal = get(row, [
    'Transação do Produto Principal',
    'Transacao do Produto Principal',
    'Transação do Order Bump',
    'Transacao do Order Bump'
  ]);

  const tipoOrderBump = get(row, [
    'tipo_do_order_bump',
    'Tipo do Order Bump'
  ]);

  if (String(tipoOrderBump || '').trim() === '1') return '1';

  if (transacaoPrincipal) return '1';

  if (ferramenta && String(ferramenta).toLowerCase().includes('order bump')) {
    return '1';
  }

  if (codigoTransacao && /C([2-9]|[1-9][0-9]+)$/.test(codigoTransacao)) {
    return '1';
  }

  return '0';
}

