];

const ignoredSourceColumns = [
  'Imposto sobre serviço Hotmart',
  'Impostos Locais',
  'Taxa de parcelamento',
  'Valor do frete bruto'
];

function getKnownSourceKeys() {
  const known = new Set();

  for (const aliases of Object.values(columns)) {
    for (const alias of aliases) {
      known.add(normalizeKey(alias));
    }
  }

  for (const col of ignoredSourceColumns) {
    known.add(normalizeKey(col));
  }

  return known;
}

function validateSourceColumns(originalRow) {
  const receivedColumns = Object.keys(originalRow).map(normalizeKey);
  const knownColumns = getKnownSourceKeys();

  const unknownColumns = receivedColumns.filter(col => !knownColumns.has(col));

  return {
    receivedColumns,
    unknownColumns
  };
}

function validateRequiredFields(data) {
  const missing = [];

  for (const col of requiredColumns) {
    if (
      data[col] === null ||
      data[col] === undefined ||
      data[col] === ''
    ) {
      missing.push(col);
    }
  }

  return missing;
}

const rows = items.flatMap(item => {
  if (Array.isArray(item.json)) return item.json;
  return [item.json];
});

const output = [];

for (const originalRow of rows) {
  const row = buildNormalizedRow(originalRow);
  const data = {};

  const columnValidation = validateSourceColumns(originalRow);

  for (const [column, aliases] of Object.entries(columns)) {
    data[column] = get(row, aliases);
  }

  data.codigo_da_transacao = get(row, [
    'codigo_da_transacao',
    'Código da transação',
    'Transação',
    'chave'
  ]);

  const missingRequiredFields = validateRequiredFields(data);

  if (missingRequiredFields.includes('codigo_da_transacao')) {
    output.push({
      json: {
        skipped: true,
        critical: true,
        reason: 'codigo_da_transacao ausente',
        missingRequiredFields,
        unknownColumns: columnValidation.unknownColumns,
        receivedColumns: columnValidation.receivedColumns,
        row: originalRow
      }
    });

    continue;
  }

  data.status_da_transacao = normalizeStatus(data.status_da_transacao);

  data.data_da_transacao = parseDate(data.data_da_transacao);

  data.confirmacao_do_pagamento = parseDate(data.confirmacao_do_pagamento);

  data.data_de_vencimento_vouchers = parseDate(data.data_de_vencimento_vouchers);

  // Regra antiga: PURCHASE_COMPLETE menos 7 dias
  if (data.status_da_transacao === 'PURCHASE_COMPLETE' && data.data_da_transacao) {
    data.data_da_transacao = minusDays(data.data_da_transacao, 7);
  }

  data.metodo_de_pagamento = normalizePayment(data.metodo_de_pagamento);

  data.venda_feita_como = normalizeRole(data.venda_feita_como);

  data.telefone = cleanPhone(data.telefone, data.pais);

  data.tipo_do_order_bump = isOrderBump(row, data.codigo_da_transacao);

  const columnNames = Object.keys(columns);

  const insertColumns = columnNames
    .map(column => `\`${column}\``)
    .join(',\n  ');

  const insertValues = columnNames
    .map(column => sqlValue(data[column]))
    .join(',\n  ');

  const updateClause = columnNames
    .filter(column => column !== 'codigo_da_transacao')
    .map(column => `\`${column}\` = VALUES(\`${column}\`)`)
    .join(',\n  ');

  const query = `
INSERT INTO ${tableName} (
  ${insertColumns}
) VALUES (
  ${insertValues}
)
ON DUPLICATE KEY UPDATE
  ${updateClause};
`.trim();

  output.push({
    json: {
      codigo_da_transacao: data.codigo_da_transacao,
      status_da_transacao: data.status_da_transacao,
      data_da_transacao: data.data_da_transacao,
      produto: data.produto,
      codigo_do_produto: data.codigo_do_produto,
      tipo_do_order_bump: data.tipo_do_order_bump,

      validation: {
        hasUnknownColumns: columnValidation.unknownColumns.length > 0,
        unknownColumns: columnValidation.unknownColumns,
        missingRequiredFields
      },

      query
    }
  });
}

return output;
